      "abbreviation": "IL",
      "title": "Personal Injury Law in Illinois | Statute of Limitations, Settlement Ranges & Rights",
      "description": "Complete guide to personal injury law in Illinois. Statute of limitations, negligence rules, average settlements, and what to do after an accident.",
      "readTime": "15 min",
      "author": "Personal Injury Attorneys at www.CasePort.io",
      "publishDate": "2024-01-15",
